/* ==========================================================================
   Action tags + SVG icon-flow (static button chrome; motion only on strokes)
   ========================================================================== */

/* Low-specificity ordinary-button baseline. Explicit border-radius on circular,
   pill, segmented, and special controls continues to win without !important. */
:where(button) {
  border-radius: var(--control-radius);
}

.tech-action-tag {
  --tag-bg: color-mix(in srgb, var(--bg-panel) 78%, var(--bg));
  position: relative;
  isolation: isolate;
  box-sizing: border-box;
  height: 28px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 5px;
  padding: 0 9px;
  border: 1px solid var(--border);
  border-radius: var(--control-radius-pill);
  background: var(--tag-bg);
  color: var(--text-muted);
  cursor: pointer;
  white-space: nowrap;
  font: inherit;
  font-size: 11px;
  line-height: 1;
  transition:
    color var(--control-motion-fast) ease,
    background var(--control-motion-fast) ease,
    border-color var(--control-motion-fast) ease,
    box-shadow var(--control-motion-fast) ease;
  overflow: visible;
  flex-shrink: 0;
}

.tech-action-tag--icon {
  width: 28px;
  min-width: 28px;
  padding: 0;
}

.tech-action-tag:hover:not(:disabled) {
  color: var(--text);
  border-color: color-mix(in srgb, var(--accent) 38%, var(--border));
  --tag-bg: color-mix(in srgb, var(--accent) 6%, var(--bg-panel));
  box-shadow: inset 0 1px color-mix(in srgb, white 20%, transparent);
}

.tech-action-tag:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
  color: var(--text);
}

.tech-action-tag.is-active,
.tech-action-tag[aria-pressed="true"],
.tech-action-tag[aria-expanded="true"] {
  color: var(--text);
  border-color: color-mix(in srgb, var(--accent) 62%, var(--border));
  --tag-bg: color-mix(in srgb, var(--accent) 12%, var(--bg));
  box-shadow:
    inset 0 0 0 1px color-mix(in srgb, var(--accent) 10%, transparent),
    0 0 12px color-mix(in srgb, var(--accent) 9%, transparent);
}

.tech-action-tag:disabled,
.tech-action-tag.is-disabled {
  opacity: 0.42;
  cursor: not-allowed;
  color: var(--text-dim);
  --tag-bg: var(--bg-panel);
  box-shadow: none;
}

/* Sidebar utility strip: 30px tags; 260px 4-col, 220px 2×2. */
.sidebar-utility-actions {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 4px;
  padding: 8px;
  flex-shrink: 0;
  border-top: 1px solid color-mix(in srgb, var(--border) 72%, transparent);
}

.sidebar-utility-tag {
  width: 100%;
  height: 30px;
  padding: 0 4px;
  font-size: 10.5px;
  gap: 4px;
}

/* 220px 2×2: IMP-02 wires narrow state via class or data attribute on the host. */
.sidebar-utility-actions.is-narrow,
.sidebar-container[data-sidebar-width="220"] .sidebar-utility-actions {
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 5px;
}

/* Top bar action tags sit in the 36px bar; labels hide on mobile via .app-top-label. */
.app-top-action-tag {
  height: 28px;
  align-self: center;
}

.app-top-actions {
  display: flex;
  align-items: center;
  gap: 4px;
}

@media (max-width: 640px) {
  .app-top-action-tag:not(.sidebar-utility-tag) {
    width: 28px;
    min-width: 28px;
    padding: 0;
  }
}

/* ---- ActionFlowIcon stroke layers ---- */
.action-flow-icon {
  display: block;
  flex: 0 0 auto;
  overflow: visible;
  pointer-events: none;
}

.action-flow-icon__base {
  fill: none;
  stroke: currentColor;
  stroke-linecap: round;
  stroke-linejoin: round;
  opacity: 0.82;
}

.action-flow-icon__overlay {
  fill: none;
  stroke-linecap: round;
  stroke-linejoin: round;
  opacity: 0;
  stroke-dasharray: var(--icon-flow-dash);
  stroke-dashoffset: 0;
  filter: drop-shadow(0 0 2px color-mix(in srgb, var(--icon-flow-a) 72%, transparent));
  pointer-events: none;
}

@keyframes action-icon-flow {
  to {
    stroke-dashoffset: var(--icon-flow-travel);
  }
}

/* Interactive (top bar): default static; flow on hover / focus / active-open. */
.tech-action-tag[data-icon-flow="interactive"]:hover:not(:disabled) .action-flow-icon__overlay,
.tech-action-tag[data-icon-flow="interactive"]:focus-visible:not(:disabled) .action-flow-icon__overlay {
  opacity: 0.95;
  animation: action-icon-flow var(--icon-flow-interactive) linear infinite;
}

.tech-action-tag[data-icon-flow="interactive"].is-active:not(:disabled) .action-flow-icon__overlay,
.tech-action-tag[data-icon-flow="interactive"][aria-pressed="true"]:not(:disabled) .action-flow-icon__overlay,
.tech-action-tag[data-icon-flow="interactive"][aria-expanded="true"]:not(:disabled) .action-flow-icon__overlay {
  opacity: 1;
  animation: action-icon-flow var(--icon-flow-active) linear infinite;
}

/* Ambient (sidebar): low-frequency staggered flow on available tags. */
.tech-action-tag[data-icon-flow="ambient"]:not(:disabled) .action-flow-icon__overlay,
.sidebar-utility-tag[data-icon-flow="ambient"]:not(:disabled) .action-flow-icon__overlay {
  opacity: 0.7;
  animation: action-icon-flow var(--icon-flow-ambient) linear infinite;
}

.sidebar-utility-actions > .tech-action-tag:nth-child(2) .action-flow-icon__overlay {
  animation-delay: -1.2s;
}
.sidebar-utility-actions > .tech-action-tag:nth-child(3) .action-flow-icon__overlay {
  animation-delay: -2.4s;
}
.sidebar-utility-actions > .tech-action-tag:nth-child(4) .action-flow-icon__overlay {
  animation-delay: -3.6s;
}

/* Explicit off + disabled: hide decorative overlay; keep base stroke. */
.tech-action-tag[data-icon-flow="off"] .action-flow-icon__overlay,
.tech-action-tag:disabled .action-flow-icon__overlay,
.tech-action-tag.is-disabled .action-flow-icon__overlay {
  opacity: 0 !important;
  animation: none !important;
  filter: none;
}

@media (prefers-reduced-motion: reduce) {
  .tech-action-tag {
    transition: none;
  }

  .action-flow-icon__overlay {
    opacity: 0 !important;
    animation: none !important;
    filter: none;
    stroke-dashoffset: 0;
  }
}

